BodyContent.ST:
//Read Breaker Statusus
{region 'Read Breakers'}
    Plant.BreakerStatus.xIncomerClosed := IncomerBreaker.State = BreakerState#CLOSED;
    Plant.BreakerStatus.xGen1Closed    := Gen1Breaker.State    = BreakerState#CLOSED;
    Plant.BreakerStatus.xGen2Closed    := Gen2Breaker.State    = BreakerState#CLOSED;
    Plant.BreakerStatus.xGen3Closed    := Gen3Breaker.State    = BreakerState#CLOSED;
    Plant.BreakerStatus.xSolarClosed   := SolarBreaker.State   = BreakerState#CLOSED;
    Plant.BreakerStatus.xBus1Closed    := Bus1Breaker.State    = BreakerState#CLOSED;
    Plant.BreakerStatus.xBus2Closed    := Bus2Breaker.State    = BreakerState#CLOSED;
    Plant.BreakerStatus.xFeeder1Closed := Feeder1Breaker.State = BreakerState#CLOSED;
    Plant.BreakerStatus.xFeeder2Closed := Feeder2Breaker.State = BreakerState#CLOSED;
{endregion}

//Read Generator Statuses
{region 'Read Generators'}
    Plant.GeneratorStatus.xGen1Available   := Gen1.Status.xAvailable;
    Plant.GeneratorStatus.xGen2Available   := Gen2.Status.xAvailable;
    Plant.GeneratorStatus.xGen3Available   := Gen3.Status.xAvailable;
    Plant.GeneratorStatus.xGen1Running     := Gen1.Status.xRunning;
    Plant.GeneratorStatus.xGen2Running     := Gen2.Status.xRunning;
    Plant.GeneratorStatus.xGen3Running     := Gen3.Status.xRunning;
    Plant.GeneratorStatus.xGen1ReadyToLoad := Gen1.Status.xReadyToLoad;
    Plant.GeneratorStatus.xGen2ReadyToLoad := Gen2.Status.xReadyToLoad;
    Plant.GeneratorStatus.xGen3ReadyToLoad := Gen3.Status.xReadyToLoad;
    Plant.GeneratorStatus.xGen1Fault       := Gen1.Status.xFault;
    Plant.GeneratorStatus.xGen2Fault       := Gen2.Status.xFault;
    Plant.GeneratorStatus.xGen3Fault       := Gen3.Status.xFault;
    Plant.GeneratorStatus.xGen1Alarm       := Gen1.Status.xAlarm;
    Plant.GeneratorStatus.xGen2Alarm       := Gen2.Status.xAlarm;
    Plant.GeneratorStatus.xGen3Alarm       := Gen3.Status.xAlarm;
    Plant.GeneratorStatus.xGen1CmdFailed   := Gen1.Status.xCmdFailed;
    Plant.GeneratorStatus.xGen2CmdFailed   := Gen2.Status.xCmdFailed;
    Plant.GeneratorStatus.xGen3CmdFailed   := Gen3.Status.xCmdFailed;
{endregion}

{region 'Breaker Logic'}
    //Default Plant Topology
    PlantNextTopology   := PlantTopology#UNKNOWN;

    //Is Utility connected?
    xUtilityConnected   := Plant.BreakerStatus.xIncomerClosed;
    //Is Solar Connected?
    xSolarConnected     := Plant.BreakerStatus.xSolarClosed;

    //How many Generators are Connected?
    uiGeneratorsConnected := 0;
        IF Plant.BreakerStatus.xGen1Closed THEN
            uiGeneratorsConnected := uiGeneratorsConnected + 1;
        END_IF;
        IF Plant.BreakerStatus.xGen2Closed THEN
            uiGeneratorsConnected := uiGeneratorsConnected + 1;
        END_IF;
        IF Plant.BreakerStatus.xGen3Closed THEN
            uiGeneratorsConnected := uiGeneratorsConnected + 1;
        END_IF;
    //Are any Generators Connected?
    xGeneratorConnected := uiGeneratorsConnected > 0;
    
    //How many Sources are Connected?
    uiSourcesConnected := 0;
        IF xUtilityConnected THEN
            uiSourcesConnected := uiSourcesConnected + 1;
        END_IF;
        IF xGeneratorConnected THEN
            uiSourcesConnected := uiSourcesConnected + 1;
        END_IF;
        IF xSolarConnected THEN
            uiSourcesConnected := uiSourcesConnected + 1;
        END_IF;
    //Are Any Sources Connected?
    xAnySourceConnected := uiSourcesConnected > 0;
    xMultipleSources    := uiSourcesConnected > 1;
    
    //Are any breakers in Fault?
    xAnyBreakerFault :=     IncomerBreaker.Status.xFault
                            OR Gen1Breaker.Status.xFault
                            OR Gen2Breaker.Status.xFault
                            OR Gen3Breaker.Status.xFault
                            OR SolarBreaker.Status.xFault
                            OR Bus1Breaker.Status.xFault
                            OR Bus2Breaker.Status.xFault
                            OR Feeder1Breaker.Status.xFault
                            OR Feeder2Breaker.Status.xFault;
    
    //Do any breakers have Invalid Feedback?
    xAnyBreakerInvalid :=   IncomerBreaker.Status.xInvalidState
                            OR Gen1Breaker.Status.xInvalidState
                            OR Gen2Breaker.Status.xInvalidState
                            OR Gen3Breaker.Status.xInvalidState
                            OR SolarBreaker.Status.xInvalidState
                            OR Bus1Breaker.Status.xInvalidState
                            OR Bus2Breaker.Status.xInvalidState
                            OR Feeder1Breaker.Status.xInvalidState
                            OR Feeder2Breaker.Status.xInvalidState;
    
    //Are any breakers in Alarm?
    xAnyBreakerAlarm :=     IncomerBreaker.Status.xAlarm
                            OR Gen1Breaker.Status.xAlarm
                            OR Gen2Breaker.Status.xAlarm
                            OR Gen3Breaker.Status.xAlarm
                            OR SolarBreaker.Status.xAlarm
                            OR Bus1Breaker.Status.xAlarm
                            OR Bus2Breaker.Status.xAlarm
                            OR Feeder1Breaker.Status.xAlarm
                            OR Feeder2Breaker.Status.xAlarm;
    
    
{endregion}

{region 'Topology Logic'}
    CASE ObserverLevel OF

        PlantObserverLevel#LEVEL_0_BREAKERS:    //Only use Breakers to determine Topology
        {region 'Level 0'}
            IF NOT xAnySourceConnected THEN
                PlantNextTopology := PlantTopology#BLACKOUT;

            ELSIF xUtilityConnected AND NOT xGeneratorConnected AND NOT xSolarConnected THEN
                PlantNextTopology := PlantTopology#UTILITY_ONLY;

            ELSIF xGeneratorConnected AND NOT xUtilityConnected AND NOT xSolarConnected THEN
                PlantNextTopology := PlantTopology#GENERATOR_ONLY;

            ELSIF xSolarConnected AND NOT xUtilityConnected AND NOT xGeneratorConnected THEN
                PlantNextTopology := PlantTopology#SOLAR_ONLY;

            ELSIF xUtilityConnected AND xSolarConnected AND NOT xGeneratorConnected THEN
                PlantNextTopology := PlantTopology#UTILITY_SOLAR;

            ELSIF xUtilityConnected AND xGeneratorConnected AND NOT xSolarConnected THEN
                PlantNextTopology := PlantTopology#UTILITY_GENERATOR;

            ELSIF xGeneratorConnected AND xSolarConnected AND NOT xUtilityConnected THEN
                PlantNextTopology := PlantTopology#GENERATOR_SOLAR;

            ELSIF xUtilityConnected AND xGeneratorConnected AND xSolarConnected THEN
                PlantNextTopology := PlantTopology#UTILITY_GENERATOR_SOLAR;

            ELSE
                PlantNextTopology := PlantTopology#UNKNOWN;
            END_IF;
        {endregion}

    ELSE
        PlantNextTopology := PlantTopology#UNKNOWN;
    END_CASE;

{endregion}

{region 'Set Plant Topology'}
    Plant.Topology := PlantNextTopology;

    CASE Plant.Topology OF
        PlantTopology#UNKNOWN:                 Plant.iTopology := 0;
        PlantTopology#BLACKOUT:                Plant.iTopology := 1;
        PlantTopology#UTILITY_ONLY:            Plant.iTopology := 2;
        PlantTopology#GENERATOR_ONLY:          Plant.iTopology := 3;
        PlantTopology#SOLAR_ONLY:              Plant.iTopology := 4;
        PlantTopology#UTILITY_SOLAR:           Plant.iTopology := 5;
        PlantTopology#UTILITY_GENERATOR:       Plant.iTopology := 6;
        PlantTopology#GENERATOR_SOLAR:         Plant.iTopology := 7;
        PlantTopology#UTILITY_GENERATOR_SOLAR: Plant.iTopology := 8;
    ELSE
        Plant.iTopology := 0;
    END_CASE;

{endregion}

{region 'Set Plant Facts'}
    //Utility Facts
    Plant.Facts.xUtilityConnected               := xUtilityConnected;
    
    //Source Facts
    Plant.Facts.xSolarConnected                 := xSolarConnected;
    Plant.Facts.xAnySourceConnected             := xAnySourceConnected;
    Plant.Facts.xMultipleSourcesConnected       := xMultipleSources;
    Plant.Facts.xMultipleGeneratorsConnected    := uiGeneratorsConnected > 1;
    
    //Bus Facts
    Plant.Facts.xUtilityGeneratorBusesConnected     :=  Plant.BreakerStatus.xBus1Closed 
                                                        AND Plant.BreakerStatus.xBus2Closed;

    Plant.Facts.xUtilityGeneratorBusesDisconnected  :=  NOT Plant.BreakerStatus.xBus1Closed 
                                                        AND NOT Plant.BreakerStatus.xBus2Closed;
    
    Plant.Facts.xUtilityGeneratorBusTiePartial      :=  Plant.BreakerStatus.xBus1Closed 
                                                        XOR Plant.BreakerStatus.xBus2Closed; 
    
    //Generator Facts
    Plant.Facts.xGeneratorConnected             :=  xGeneratorConnected;
    Plant.Facts.xGeneratorAvailable             :=  Plant.GeneratorStatus.xGen1Available
                                                    OR Plant.GeneratorStatus.xGen2Available
                                                    OR Plant.GeneratorStatus.xGen3Available;
                                                   
    //Breaker Facts
    Plant.Facts.xBreakerFaultPresent            :=  xAnyBreakerFault;
    Plant.Facts.xBreakerInvalidPresent          :=  xAnyBreakerInvalid;
    Plant.Facts.xBreakerAlarmPresent            :=  xAnyBreakerAlarm;
    
    //Transfer Facts
    Plant.Facts.xUtilityGeneratorParallel       :=  xUtilityConnected 
                                                    AND xGeneratorConnected
                                                    AND Plant.Facts.xUtilityGeneratorBusesConnected;
    
    Plant.Facts.xUtilitySolarParallel           :=  xUtilityConnected
                                                    AND xSolarConnected;
    
    Plant.Facts.xGeneratorSolarParallel         :=  xGeneratorConnected
                                                    AND xSolarConnected
                                                    AND Plant.Facts.xUtilityGeneratorBusesConnected;
    
    Plant.Facts.xParallelSourcesActive          :=  Plant.Facts.xUtilityGeneratorParallel
                                                    OR Plant.Facts.xUtilitySolarParallel
                                                    OR Plant.Facts.xGeneratorSolarParallel;
    
{endregion}

{region 'Clear Messages'}
    //Clear Previous Messages
    FOR uiMessageIndex := 1 TO 10 DO
        Plant.Messages[uiMessageIndex].xActive   := FALSE;
        Plant.Messages[uiMessageIndex].Severity  := PlantMessageSeverity#INFO;
        Plant.Messages[uiMessageIndex].iSeverity := 0;
        Plant.Messages[uiMessageIndex].Code      := PlantMessageCode#NONE;
        Plant.Messages[uiMessageIndex].iCode     := 0;
        Plant.Messages[uiMessageIndex].sMessage  := '';
    END_FOR;
    Plant.uiMessageCount := 0;
{endregion}

{region 'Alarm Messages'}
    // Highest priority: at least one breaker has a fault.
    IF Plant.Facts.xBreakerFaultPresent THEN
        IF Plant.uiMessageCount < 10 THEN
            Plant.uiMessageCount := Plant.uiMessageCount + 1;

            Plant.Messages[Plant.uiMessageCount].xActive   := TRUE;
            Plant.Messages[Plant.uiMessageCount].Severity  := PlantMessageSeverity#ALARM;
            Plant.Messages[Plant.uiMessageCount].iSeverity := 2;
            Plant.Messages[Plant.uiMessageCount].Code      := PlantMessageCode#BREAKER_FAULT_PRESENT;
            Plant.Messages[Plant.uiMessageCount].iCode     := 12;
            Plant.Messages[Plant.uiMessageCount].sMessage  := 'Breaker fault present';
        END_IF;
    END_IF;
    
    // Highest priority: at least one breaker has invalid feedback.
    IF Plant.Facts.xBreakerInvalidPresent THEN
        IF Plant.uiMessageCount < 10 THEN
            Plant.uiMessageCount := Plant.uiMessageCount + 1;

            Plant.Messages[Plant.uiMessageCount].xActive   := TRUE;
            Plant.Messages[Plant.uiMessageCount].Severity  := PlantMessageSeverity#ALARM;
            Plant.Messages[Plant.uiMessageCount].iSeverity := 2;
            Plant.Messages[Plant.uiMessageCount].Code      := PlantMessageCode#BREAKER_INVALID_PRESENT;
            Plant.Messages[Plant.uiMessageCount].iCode     := 13;
            Plant.Messages[Plant.uiMessageCount].sMessage  := 'Breaker invalid feedback present';
        END_IF;
    END_IF;

    // Lower priority: generic breaker alarm.
    // Only show this if there is no breaker fault or invalid feedback already shown.
    IF Plant.Facts.xBreakerAlarmPresent
    AND NOT Plant.Facts.xBreakerFaultPresent
    AND NOT Plant.Facts.xBreakerInvalidPresent THEN

        IF Plant.uiMessageCount < 10 THEN
            Plant.uiMessageCount := Plant.uiMessageCount + 1;

            Plant.Messages[Plant.uiMessageCount].xActive   := TRUE;
            Plant.Messages[Plant.uiMessageCount].Severity  := PlantMessageSeverity#WARNING;
            Plant.Messages[Plant.uiMessageCount].iSeverity := 1;
            Plant.Messages[Plant.uiMessageCount].Code      := PlantMessageCode#BREAKER_ALARM_PRESENT;
            Plant.Messages[Plant.uiMessageCount].iCode     := 14;
            Plant.Messages[Plant.uiMessageCount].sMessage  := 'Breaker alarm present';
        END_IF;
    END_IF;

{endregion}

{region 'Source Messages'}
    //Utility Connected
    IF Plant.Facts.xUtilityConnected THEN
        IF Plant.uiMessageCount < 10 THEN
            Plant.uiMessageCount := Plant.uiMessageCount + 1;

            Plant.Messages[Plant.uiMessageCount].xActive   := TRUE;
            Plant.Messages[Plant.uiMessageCount].Severity  := PlantMessageSeverity#INFO;
            Plant.Messages[Plant.uiMessageCount].iSeverity := 0;
            Plant.Messages[Plant.uiMessageCount].Code      := PlantMessageCode#UTILITY_CONNECTED;
            Plant.Messages[Plant.uiMessageCount].iCode     := 9;
            Plant.Messages[Plant.uiMessageCount].sMessage  := 'Utility source connected';
        END_IF;
    END_IF;
    //Generator Connected
    IF Plant.Facts.xGeneratorConnected THEN
        IF Plant.uiMessageCount < 10 THEN
            Plant.uiMessageCount := Plant.uiMessageCount + 1;
    
            Plant.Messages[Plant.uiMessageCount].xActive   := TRUE;
            Plant.Messages[Plant.uiMessageCount].Severity  := PlantMessageSeverity#INFO;
            Plant.Messages[Plant.uiMessageCount].iSeverity := 0;
            Plant.Messages[Plant.uiMessageCount].Code      := PlantMessageCode#GENERATOR_CONNECTED;
            Plant.Messages[Plant.uiMessageCount].iCode     := 10;
            Plant.Messages[Plant.uiMessageCount].sMessage  := 'Generator source connected';
        END_IF;
    END_IF;  
    //Solar Connected
    IF Plant.Facts.xSolarConnected THEN
        IF Plant.uiMessageCount < 10 THEN
            Plant.uiMessageCount := Plant.uiMessageCount + 1;

            Plant.Messages[Plant.uiMessageCount].xActive   := TRUE;
            Plant.Messages[Plant.uiMessageCount].Severity  := PlantMessageSeverity#INFO;
            Plant.Messages[Plant.uiMessageCount].iSeverity := 0;
            Plant.Messages[Plant.uiMessageCount].Code      := PlantMessageCode#SOLAR_CONNECTED;
            Plant.Messages[Plant.uiMessageCount].iCode     := 11;
            Plant.Messages[Plant.uiMessageCount].sMessage  := 'Solar source connected';
        END_IF;
    END_IF;
{endregion}

{region 'Bus Section Messages'}
    // Utility & generator bus sections connected
    IF Plant.Facts.xUtilityGeneratorBusesConnected THEN
        IF Plant.uiMessageCount < 10 THEN
            Plant.uiMessageCount := Plant.uiMessageCount + 1;
    
            Plant.Messages[Plant.uiMessageCount].xActive   := TRUE;
            Plant.Messages[Plant.uiMessageCount].Severity  := PlantMessageSeverity#INFO;
            Plant.Messages[Plant.uiMessageCount].iSeverity := 0;
            Plant.Messages[Plant.uiMessageCount].Code      := PlantMessageCode#UTILITY_GENERATOR_BUSES_CONNECTED;
            Plant.Messages[Plant.uiMessageCount].iCode     := 15;
            Plant.Messages[Plant.uiMessageCount].sMessage  := 'Utility/generator buses connected';
        END_IF;
    END_IF;
    
    // Utility & generator bus sections disconnected
    IF Plant.Facts.xUtilityGeneratorBusesDisconnected THEN
        IF Plant.uiMessageCount < 10 THEN
            Plant.uiMessageCount := Plant.uiMessageCount + 1;
    
            Plant.Messages[Plant.uiMessageCount].xActive   := TRUE;
            Plant.Messages[Plant.uiMessageCount].Severity  := PlantMessageSeverity#INFO;
            Plant.Messages[Plant.uiMessageCount].iSeverity := 0;
            Plant.Messages[Plant.uiMessageCount].Code      := PlantMessageCode#UTILITY_GENERATOR_BUSES_DISCONNECTED;
            Plant.Messages[Plant.uiMessageCount].iCode     := 16;
            Plant.Messages[Plant.uiMessageCount].sMessage  := 'Utility/generator buses disconnected';
        END_IF;
    END_IF;
    
    // One bus tie breaker closed, the other open
    IF Plant.Facts.xUtilityGeneratorBusTiePartial THEN
        IF Plant.uiMessageCount < 10 THEN
            Plant.uiMessageCount := Plant.uiMessageCount + 1;
    
            Plant.Messages[Plant.uiMessageCount].xActive   := TRUE;
            Plant.Messages[Plant.uiMessageCount].Severity  := PlantMessageSeverity#WARNING;
            Plant.Messages[Plant.uiMessageCount].iSeverity := 1;
            Plant.Messages[Plant.uiMessageCount].Code      := PlantMessageCode#UTILITY_GENERATOR_BUS_TIE_PARTIAL;
            Plant.Messages[Plant.uiMessageCount].iCode     := 17;
            Plant.Messages[Plant.uiMessageCount].sMessage  := 'Utility/generator bus tie partial';
        END_IF;
    END_IF;
{endregion}

{region 'Condition Messages'}

    //Blackout - No sources Connected
    IF Plant.Topology = PlantTopology#BLACKOUT THEN
        IF Plant.uiMessageCount < 10 THEN
            Plant.uiMessageCount := Plant.uiMessageCount + 1;

            Plant.Messages[Plant.uiMessageCount].xActive   := TRUE;
            Plant.Messages[Plant.uiMessageCount].Severity  := PlantMessageSeverity#WARNING;
            Plant.Messages[Plant.uiMessageCount].iSeverity := 1;
            Plant.Messages[Plant.uiMessageCount].Code      := PlantMessageCode#BLACKOUT;
            Plant.Messages[Plant.uiMessageCount].iCode     := 1;
            Plant.Messages[Plant.uiMessageCount].sMessage  := 'No source connected';
        END_IF;
    END_IF;
    
    //Unknow Plant Topology
    IF Plant.Topology = PlantTopology#UNKNOWN THEN
        IF Plant.uiMessageCount < 10 THEN
            Plant.uiMessageCount := Plant.uiMessageCount + 1;

            Plant.Messages[Plant.uiMessageCount].xActive   := TRUE;
            Plant.Messages[Plant.uiMessageCount].Severity  := PlantMessageSeverity#ALARM;
            Plant.Messages[Plant.uiMessageCount].iSeverity := 2;
            Plant.Messages[Plant.uiMessageCount].Code      := PlantMessageCode#UNKNOWN_TOPOLOGY;
            Plant.Messages[Plant.uiMessageCount].iCode     := 2;
            Plant.Messages[Plant.uiMessageCount].sMessage  := 'Unknown plant topology';
        END_IF;
    END_IF;

    //Multiple Sources Connected in Parallel
    IF Plant.Facts.xParallelSourcesActive THEN
        IF Plant.uiMessageCount < 10 THEN
            Plant.uiMessageCount := Plant.uiMessageCount + 1;

            Plant.Messages[Plant.uiMessageCount].xActive   := TRUE;
            Plant.Messages[Plant.uiMessageCount].Severity  := PlantMessageSeverity#WARNING;
            Plant.Messages[Plant.uiMessageCount].iSeverity := 1;
            Plant.Messages[Plant.uiMessageCount].Code      := PlantMessageCode#MULTIPLE_SOURCES_CONNECTED;
            Plant.Messages[Plant.uiMessageCount].iCode     := 3;
            Plant.Messages[Plant.uiMessageCount].sMessage  := 'Multiple sources connected';
        END_IF;
    END_IF;
    
    //Utility & Generator Connected in Parallel
    IF Plant.Facts.xUtilityGeneratorParallel THEN
        IF Plant.uiMessageCount < 10 THEN
            Plant.uiMessageCount := Plant.uiMessageCount + 1;

            Plant.Messages[Plant.uiMessageCount].xActive   := TRUE;
            Plant.Messages[Plant.uiMessageCount].Severity  := PlantMessageSeverity#WARNING;
            Plant.Messages[Plant.uiMessageCount].iSeverity := 1;
            Plant.Messages[Plant.uiMessageCount].Code      := PlantMessageCode#UTILITY_GENERATOR_PARALLEL;
            Plant.Messages[Plant.uiMessageCount].iCode     := 4;
            Plant.Messages[Plant.uiMessageCount].sMessage  := 'Utility and generator sources connected';
        END_IF;
    END_IF;

    //Utility & Solar Connected in Parallel
    IF Plant.Facts.xUtilitySolarParallel THEN
        IF Plant.uiMessageCount < 10 THEN
            Plant.uiMessageCount := Plant.uiMessageCount + 1;

            Plant.Messages[Plant.uiMessageCount].xActive   := TRUE;
            Plant.Messages[Plant.uiMessageCount].Severity  := PlantMessageSeverity#WARNING;
            Plant.Messages[Plant.uiMessageCount].iSeverity := 1;
            Plant.Messages[Plant.uiMessageCount].Code      := PlantMessageCode#UTILITY_SOLAR_PARALLEL;
            Plant.Messages[Plant.uiMessageCount].iCode     := 5;
            Plant.Messages[Plant.uiMessageCount].sMessage  := 'Utility and solar sources connected';
        END_IF;
    END_IF;

    //Generator & Solar Connected in Parallel
    IF Plant.Facts.xGeneratorSolarParallel THEN
        IF Plant.uiMessageCount < 10 THEN
            Plant.uiMessageCount := Plant.uiMessageCount + 1;

            Plant.Messages[Plant.uiMessageCount].xActive   := TRUE;
            Plant.Messages[Plant.uiMessageCount].Severity  := PlantMessageSeverity#WARNING;
            Plant.Messages[Plant.uiMessageCount].iSeverity := 1;
            Plant.Messages[Plant.uiMessageCount].Code      := PlantMessageCode#GENERATOR_SOLAR_PARALLEL;
            Plant.Messages[Plant.uiMessageCount].iCode     := 6;
            Plant.Messages[Plant.uiMessageCount].sMessage  := 'Generator and solar sources connected';
        END_IF;
    END_IF;

    //Multiple Generators Connected
    IF Plant.Facts.xMultipleGeneratorsConnected THEN
        IF Plant.uiMessageCount < 10 THEN
            Plant.uiMessageCount := Plant.uiMessageCount + 1;

            Plant.Messages[Plant.uiMessageCount].xActive   := TRUE;
            Plant.Messages[Plant.uiMessageCount].Severity  := PlantMessageSeverity#INFO;
            Plant.Messages[Plant.uiMessageCount].iSeverity := 0;
            Plant.Messages[Plant.uiMessageCount].Code      := PlantMessageCode#MULTIPLE_GENERATORS_CONNECTED;
            Plant.Messages[Plant.uiMessageCount].iCode     := 7;
            Plant.Messages[Plant.uiMessageCount].sMessage  := 'Multiple generators connected';
        END_IF;
    END_IF;

    //Requested Observer Complexity Level not Supported
    IF ObserverLevel <> PlantObserverLevel#LEVEL_0_BREAKERS THEN
        IF Plant.uiMessageCount < 10 THEN
            Plant.uiMessageCount := Plant.uiMessageCount + 1;

            Plant.Messages[Plant.uiMessageCount].xActive   := TRUE;
            Plant.Messages[Plant.uiMessageCount].Severity  := PlantMessageSeverity#ALARM;
            Plant.Messages[Plant.uiMessageCount].iSeverity := 2;
            Plant.Messages[Plant.uiMessageCount].Code      := PlantMessageCode#UNSUPPORTED_OBSERVER_LEVEL;
            Plant.Messages[Plant.uiMessageCount].iCode     := 8;
            Plant.Messages[Plant.uiMessageCount].sMessage  := 'Unsupported observer level';
        END_IF;
    END_IF;

{endregion}
